/**
 * @summary Verify a hash against the blockchain registry
 */
export const getVerifyHashUrl = () => {
  return `/api/verify/hash`;
};

export const verifyHash = async (
  verifyHashBody: VerifyHashBody,
  options?: RequestInit,
): Promise<VerificationResult> => {
  return customFetch<VerificationResult>(getVerifyHashUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(verifyHashBody),
  });
};

export const getVerifyHashMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof verifyHash>>,
    TError,
    { data: BodyType<VerifyHashBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof verifyHash>>,
  TError,
  { data: BodyType<VerifyHashBody> },
  TContext
> => {
  const mutationKey = ["verifyHash"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof verifyHash>>,
    { data: BodyType<VerifyHashBody> }
  > = (props) => {
    const { data } = props ?? {};

    return verifyHash(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type VerifyHashMutationResult = NonNullable<
  Awaited<ReturnType<typeof verifyHash>>
>;
export type VerifyHashMutationBody = BodyType<VerifyHashBody>;
export type VerifyHashMutationError = ErrorType<unknown>;

/**
 * @summary Verify a hash against the blockchain registry
 */
export const useVerifyHash = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof verifyHash>>,
    TError,
    { data: BodyType<VerifyHashBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof verifyHash>>,
  TError,
  { data: BodyType<VerifyHashBody> },
  TContext
> => {
  return useMutation(getVerifyHashMutationOptions(options));
};
